You are implementing Task 7 of the Digital Loyalty Card App.

**Context:** Monorepo at C:\Users\User\loyalty-app. Next.js dashboard at apps/dashboard with login page, Supabase SSR helpers, middleware auth guard. Now we need merchant registration and a useMerchant hook.

**TASK: Auth — Merchant Dashboard (Email)**

**Step 1: Create register page**
Create `apps/dashboard/src/app/register/page.tsx`:
```typescript
'use client';
import { useState } from 'react';
import { useRouter } from 'next/navigation';
import { createClient } from '@/lib/supabase/client';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import Link from 'next/link';

export default function RegisterPage() {
  const [name, setName] = useState('');
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [businessName, setBusinessName] = useState('');
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);
  const router = useRouter();
  const supabase = createClient();

  async function handleRegister(e: React.FormEvent) {
    e.preventDefault();
    setLoading(true);
    setError('');
    const { data, error: authError } = await supabase.auth.signUp({
      email, password,
      options: { data: { name, business_name: businessName, role: 'merchant' } },
    });
    if (authError) { setError(authError.message); setLoading(false); return; }
    if (data.user) {
      const { error: merchantError } = await supabase.from('merchants').insert({
        user_id: data.user.id,
        name: businessName,
      });
      if (merchantError) { setError(merchantError.message); setLoading(false); return; }
    }
    router.push('/');
    router.refresh();
  }

  return (
    <div className="flex min-h-screen items-center justify-center bg-gray-50">
      <Card className="w-full max-w-md">
        <CardHeader><CardTitle>Create Merchant Account</CardTitle></CardHeader>
        <CardContent>
          <form onSubmit={handleRegister} className="space-y-4">
            <div><Label>Your Name</Label><Input value={name} onChange={(e) => setName(e.target.value)} required /></div>
            <div><Label>Business Name</Label><Input value={businessName} onChange={(e) => setBusinessName(e.target.value)} required /></div>
            <div><Label>Email</Label><Input type="email" value={email} onChange={(e) => setEmail(e.target.value)} required /></div>
            <div><Label>Password</Label><Input type="password" value={password} onChange={(e) => setPassword(e.target.value)} required /></div>
            {error && <p className="text-sm text-red-500">{error}</p>}
            <Button type="submit" className="w-full" disabled={loading}>{loading ? 'Creating...' : 'Create Account'}</Button>
          </form>
          <p className="text-sm text-center mt-4 text-gray-500">Already have an account? <Link href="/login" className="text-indigo-600 hover:underline">Sign In</Link></p>
        </CardContent>
      </Card>
    </div>
  );
}
```

**Step 2: Create useMerchant hook**
Create `apps/dashboard/src/hooks/use-merchant.ts`:
```typescript
'use client';
import { useEffect, useState } from 'react';
import { createClient } from '@/lib/supabase/client';
import type { Merchant } from '@loyalty/shared';

export function useMerchant() {
  const [merchant, setMerchant] = useState<Merchant | null>(null);
  const [loading, setLoading] = useState(true);
  const supabase = createClient();

  useEffect(() => {
    async function fetch() {
      const { data: { user } } = await supabase.auth.getUser();
      if (!user) { setLoading(false); return; }
      const { data } = await supabase.from('merchants').select('*').eq('user_id', user.id).single();
      setMerchant(data);
      setLoading(false);
    }
    fetch();
  }, []);

  return { merchant, loading };
}
```

